In that case, you can create a separate index cache for each index file. This way, when you remove old index files, you can also remove the corresponding cache, which will help to prevent memory leaks.

Here's a simple example of how you can implement this:

```python
import os
import pickle

class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        os.makedirs(self.cache_dir, exist_ok=True)

    def get_cache_file(self, index_file):
        return os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")

    def load_cache(self, index_file):
        cache_file = self.get_cache_file(index_file)
        if os.path.exists(cache_file):
            with open(cache_file, "rb") as f:
                return pickle.load(f)
        return None

    def save_cache(self, index_file, data):
        cache_file = self.get_cache_file(index_file)
        with open(cache_file, "wb") as f:
            pickle.dump(data, f)

    def delete_cache(self, index_file):
        cache_file = self.get_cache_file(index_file)
        if os.path.exists(cache_file):
            os.remove(cache_file)
```

